    warn "无法识别操作系统 /etc/os-release 文件未找到"
    return 1
  fi

  # shellcheck disable=SC1091
  . /etc/os-release
  if [ "$ID" != "debian" ] && [[ "${ID_LIKE:-}" != *debian* ]]; then
    warn "操作系统不是基于 Debian"
    return 1
  fi

  DEBIAN_VERSION_MAJOR="${VERSION_ID%%.*}"
  log "操作系统基于 Debian"
  return 0
}

github_proxy_fallback_url() {
  local url="$1"

  case "$url" in
    https://gh-proxy.com/*)
      printf 'https://%s\n' "${url#https://gh-proxy.com/}"
      ;;
    http://gh-proxy.com/*)
      printf 'https://%s\n' "${url#http://gh-proxy.com/}"
      ;;
    https://ghfast.top/https://*)
      printf 'https://%s\n' "${url#https://ghfast.top/https://}"
      ;;
    https://ghfast.top/http://*)
      printf 'http://%s\n' "${url#https://ghfast.top/http://}"
      ;;
    *)
      return 1
      ;;
  esac
}

download_to() {
  local url="$1"
  local output_path="$2"
  local fallback_url
  local exit_code
  local err_file
  local fallback_err_file

  fallback_url="$(github_proxy_fallback_url "$url" 2>/dev/null || true)"

  if command_exists curl; then
    if [ -n "$fallback_url" ] && [ "$fallback_url" != "$url" ]; then
      err_file="$(mktemp)"
      fallback_err_file="$(mktemp)"

      curl -fsSL "$url" -o "$output_path" 2>"$err_file" && {
        rm -f "$err_file" "$fallback_err_file"
        return 0
      }
      exit_code=$?

      warn "加速地址下载失败，尝试回退到官方地址：$fallback_url"
      curl -fsSL "$fallback_url" -o "$output_path" 2>"$fallback_err_file" && {
        rm -f "$err_file" "$fallback_err_file"
        return 0
      }

      cat "$err_file" >&2
      cat "$fallback_err_file" >&2
      rm -f "$err_file" "$fallback_err_file"
      return "$exit_code"
    fi

    curl -fsSL "$url" -o "$output_path" && return 0
    exit_code=$?
    return "$exit_code"
  fi

  if command_exists wget; then
    if [ -n "$fallback_url" ] && [ "$fallback_url" != "$url" ]; then
      wget -q "$url" -O "$output_path" && return 0
      exit_code=$?
      warn "加速地址下载失败，尝试回退到官方地址：$fallback_url"
      wget -q "$fallback_url" -O "$output_path"
      return $?
    fi

    wget -q "$url" -O "$output_path" && return 0
    exit_code=$?
    return "$exit_code"
  fi

  warn "请先安装 curl 或 wget"
  return 1
}

