run_remote_script() {
  local url="$1"
  local script_path
  local script_name
  local exit_code

  script_name="$(basename "${url%%\?*}")"
  script_name="${script_name:-remote.sh}"
  script_path="$DOWNLOAD_DIR/$script_name"

  download_to "$url" "$script_path" || return 1
  run_privileged chmod +x "$script_path"

  if [[ "$url" == *".sh" ]] || head -n 1 "$script_path" | grep -q '^#!'; then
    bash "$script_path"
  else
    sh "$script_path"
  fi
  exit_code=$?

  return "$exit_code"
}

set_sysctl_value() {
  local key="$1"
  local value="$2"
  local sysctl_file="/etc/sysctl.conf"

  if run_privileged grep -q "^${key}=" "$sysctl_file"; then
    run_privileged sed -i "s/^${key}=.*/${key}=${value}/" "$sysctl_file"
  else
    printf '%s=%s\n' "$key" "$value" | run_privileged tee -a "$sysctl_file" >/dev/null
  fi

  run_privileged sysctl -p
}

install_asset_file() {
  local asset_key="$1"
  local output_path="$2"
  local owner="${3:-$TARGET_USER}"
  local mode="${4:-644}"

  ensure_dir "$(dirname "$output_path")" "${owner:-}"
  write_embedded_asset "$asset_key" "$output_path" || return 1
  run_privileged chmod "$mode" "$output_path"
  if [ -n "$owner" ]; then
    set_file_owner "$output_path" "$owner"
  fi
}

install_asset_file_privileged() {
  local asset_key="$1"
  local output_path="$2"
  local owner="${3:-root}"
  local mode="${4:-644}"
  local temp_file

  temp_file="$(mktemp)"
  write_embedded_asset "$asset_key" "$temp_file" || {
    rm -f "$temp_file"
    return 1
  }

  ensure_privileged_dir "$(dirname "$output_path")" "$owner"
  run_privileged cp "$temp_file" "$output_path"
  run_privileged chmod "$mode" "$output_path"
  if [ -n "$owner" ]; then
    run_privileged chown "$owner:$(id -gn "$owner")" "$output_path"
  fi

  rm -f "$temp_file"
}

github_proxy_set() {
  local saved_value
  local persist_choice

  saved_value="$(github_proxy_preference 2>/dev/null || true)"
  if [ "$saved_value" = "on" ] || [ "$saved_value" = "off" ]; then
    apply_github_proxy_preference "$saved_value"
    return 0
  fi

  persist_choice="1"
  if [ "$saved_value" = "ask" ]; then
    persist_choice="0"
  fi

  while true; do
    read -r -p "是否启用 Github 国内加速? [Y/n] " input
    case "$input" in
      ""|[yY])
        if [ "$persist_choice" = "1" ]; then
          set_github_proxy_preference "on"
        fi
        apply_github_proxy_preference "on"
        break
        ;;
      [nN])
        if [ "$persist_choice" = "1" ]; then
          set_github_proxy_preference "off"
        fi
        apply_github_proxy_preference "off"
        break
        ;;
      *)
        log "错误选项：$input"
        ;;
    esac
  done
}

# Shared interactive helpers.

print_section() {
  printf '\n---------- %s ----------\n\n' "$1"
}

print_divider() {
  printf '%s\n' "----------------------------------------------------------------------"
}

pause_enter() {
  read -r -p "按回车键继续" _
}

prompt_yes_no_default_yes() {
  local prompt_text="$1"

  while true; do
    read -r -p "$prompt_text [Y/n] " input
    case "$input" in
      ""|[yY]) return 0 ;;
      [nN]) return 1 ;;
      *) log "错误选项：$input" ;;
    esac
  done
}

prompt_yes_no_default_no() {
  local prompt_text="$1"

  while true; do
    read -r -p "$prompt_text [y/N] " input
    case "$input" in
      [yY]) return 0 ;;
      ""|[nN]) return 1 ;;
      *) log "错误选项：$input" ;;
    esac
  done
}

prompt_with_default() {
  local prompt_text="$1"
  local default_value="$2"
  local user_input

  read -r -p "$prompt_text（默认：$default_value）: " user_input
  if [ -z "$user_input" ]; then
    printf '%s\n' "$default_value"
  else
    printf '%s\n' "$user_input"
  fi
}

# Menu registry used by the main entrypoint.

declare -a MODULE_IDS=()
declare -a MODULE_TITLES=()
declare -a MODULE_DESCRIPTIONS=()
declare -a MODULE_HANDLERS=()

register_module() {
  local module_id="$1"
  local title="$2"
  local description="$3"
  local handler="$4"

  MODULE_IDS+=("$module_id")
  MODULE_TITLES+=("$title")
  MODULE_DESCRIPTIONS+=("$description")
  MODULE_HANDLERS+=("$handler")
}

module_index_by_id() {
  local module_id="$1"
  local i

  for i in "${!MODULE_IDS[@]}"; do
    if [ "${MODULE_IDS[$i]}" = "$module_id" ]; then
      printf '%s\n' "$i"
      return 0
    fi
  done

  return 1
}

run_module() {
  local module_id="$1"
  local module_index
  local handler

  module_index="$(module_index_by_id "$module_id" 2>/dev/null || true)"
  if [ -z "$module_index" ]; then
    warn "未找到模块：$module_id"
    return 1
  fi

  handler="${MODULE_HANDLERS[$module_index]}"
  "$handler"
}

