  caddy:
    image: caddy:2-alpine
    container_name: caddy
    restart: always
    ports:
      - 80:80
      - 443:443
    extra_hosts:
      - "host.docker.internal:host-gateway"
    volumes:
      - ./Caddyfile:/etc/caddy/Caddyfile:ro
      - ./data:/data
      - ./config:/config

__SETUP_ASSET_docker_caddy_yml__
      ;;
    "docker/code-server.yml")
      cat >"$output_path" <<'__SETUP_ASSET_docker_code_server_yml__'
