# FTP 服务器
# 部署目录：/root/docker-compose/pure-ftpd/docker-compose.yml

services:
  ftpd_server:
    image: stilliard/pure-ftpd
    container_name: pure-ftpd
    ports:
      - 21:21 # FTP 主动端口
      - 30000-30009:30000-30009 # FTP 被动端口
    volumes:
      - ./web_root:/home/username/ # FTP 服务器根目录映射
      - ./ftp_passwd:/etc/pure-ftpd/passwd # FTP 密码（已加密）
    environment:
      # - PUBLICHOST=tsanfer.com
      - FTP_USER_NAME
      - FTP_USER_PASS
      - FTP_USER_HOME=/home/username # FTP 服务器根目录，在容器内的位置
    restart: always

__SETUP_ASSET_docker_pure_ftpd_yml__
